mapper.insert:

    SELECT SEQ_NOTICE.NEXTVAL FROM DUAL

INSERT INTO TBL_NOTICE (
ID, NOTICE_TITLE, NOTICE_CONTENT, NOTICE_CATEGORY,
NOTICE_PINNED, NOTICE_FILE_URL, USER_ID
)
VALUES (
#{id}, #{noticeTitle}, #{noticeContent}, #{noticeCategory},
#{noticePinned}, #{noticeFileUrl}, #{userId}
)

mapper.select:
SELECT ID, NOTICE_TITLE, NOTICE_CATEGORY, NOTICE_PINNED, NOTICE_CREATE_AT FROM TBL_NOTICE
AND NOTICE_CATEGORY = #{noticeCategory}
ORDER BY NOTICE_PINNED DESC, ID DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY
